// Unit 20. Antes de Eso
// Pluscuamperfecto & Reported Speech

export default {n:20,lang:"es",srcLang:"en",track:"v2",title:"Antes de Eso",sub:"Pluscuamperfecto & Reported Speech",icon:"⏮️",level:"B1.2",color:"#7B5EE8",lessons:[
  {id:"esp20l1",title:"Participios Pasados",icon:"🔧",xp:20,board:true,steps:[
        {type:"intro",title:"Participios Pasados",desc:"Learn how to form past participles in Spanish. These are essential building blocks for compound tenses.",goals:["Form regular past participles with -ado/-ido","Learn key irregular past participles","Recognize participles in context"]},
        {type:"teach",trg:"el participio pasado",src:"the past participle",pos:"verb",gender:null,phonetic:"par-tee-THEE-pyoh pah-SAH-doh",note:"-ar verbs: -ado (hablado)\n-er/-ir verbs: -ido (comido, vivido)",example:"A: ¿Sabes formar participios?\nB: Claro. Hablar se convierte en hablado.\nA: ¿Y comer?\nB: Comer se convierte en comido.",exampleSrc:"A: Do you know how to form participles?\nB: Of course. Hablar becomes hablado.\nA: And comer?\nB: Comer becomes comido.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"hablado",src:"spoken/talked",pos:"noun",gender:null,phonetic:"ah-BLAH-doh",note:"Regular -ar participle: hablar to hablado.",example:"A: ¿Has hablado con tu madre?\nB: Si, ya he hablado con ella.\nA: ¿Que te ha dicho?\nB: Que todo esta bien.",exampleSrc:"A: Have you spoken with your mother?\nB: Yes, I've already spoken with her.\nA: What did she say?\nB: That everything is fine.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"comido",src:"eaten",pos:"noun",gender:null,phonetic:"koh-MEE-doh",note:"Regular -er participle: comer to comido.",example:"A: ¿Ya has comido?\nB: No, todavia no he comido nada.\nA: Hay pizza en la cocina.\nB: Perfecto, gracias.",exampleSrc:"A: Have you eaten yet?\nB: No, I haven't eaten anything yet.\nA: There's pizza in the kitchen.\nB: Perfect, thanks.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"vivido",src:"lived",pos:"noun",gender:null,phonetic:"bee-BEE-doh",note:"Regular -ir participle: vivir to vivido.",example:"A: ¿Has vivido en otro pais?\nB: Si, he vivido en Mexico dos anos.\nA: ¿Te gusto?\nB: Me encanto la experiencia.",exampleSrc:"A: Have you lived in another country?\nB: Yes, I've lived in Mexico for two years.\nA: Did you like it?\nB: I loved the experience.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Regular Participle Formation",deepDive:"The past participle is used in compound tenses (he hablado), passive voice (fue construido), and as adjectives (la puerta cerrada). In compound tenses, the participle never changes form.",text:"-AR verbs: drop -ar, add -ado\n  hablar to hablado, estudiar to estudiado\n-ER verbs: drop -er, add -ido\n  comer to comido, beber to bebido\n-IR verbs: drop -ir, add -ido\n  vivir to vivido, salir to salido"},
        {type:"teach",trg:"hecho",src:"done/made",pos:"noun",gender:null,phonetic:"EH-choh",note:"Irregular participle of hacer. One of the most common.",example:"A: ¿Que has hecho hoy?\nB: He hecho la compra y la limpieza.\nA: Yo no he hecho nada.\nB: A veces es bueno descansar.",exampleSrc:"A: What have you done today?\nB: I've done the shopping and the cleaning.\nA: I haven't done anything.\nB: Sometimes it's good to rest.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"dicho",src:"said/told",pos:"noun",gender:null,phonetic:"DEE-choh",note:"Irregular participle of decir.",example:"A: ¿Que te ha dicho el profesor?\nB: Me ha dicho que el examen es el viernes.\nA: Nadie me ha dicho nada.\nB: Pues ahora ya lo sabes.",exampleSrc:"A: What did the teacher tell you?\nB: He told me the exam is on Friday.\nA: Nobody told me anything.\nB: Well, now you know.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"escrito",src:"written",pos:"noun",gender:null,phonetic:"ehs-KREE-toh",note:"Irregular participle of escribir.",example:"A: ¿Has escrito el informe?\nB: Si, lo he escrito esta manana.\nA: ¿Me lo puedes enviar?\nB: Te lo envio ahora mismo.",exampleSrc:"A: Have you written the report?\nB: Yes, I wrote it this morning.\nA: Can you send it to me?\nB: I'll send it to you right now.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"visto",src:"seen",pos:"noun",gender:null,phonetic:"BEES-toh",note:"Irregular participle of ver.",example:"A: ¿Has visto la nueva pelicula?\nB: No, todavia no la he visto.\nA: Es muy buena, te la recomiendo.\nB: La vere este fin de semana.",exampleSrc:"A: Have you seen the new movie?\nB: No, I haven't seen it yet.\nA: It's very good, I recommend it.\nB: I'll watch it this weekend.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"puesto",src:"put/placed",pos:"noun",gender:null,phonetic:"PWES-toh",note:"Irregular participle of poner.",example:"A: ¿Donde has puesto las llaves?\nB: Las he puesto en la mesa.\nA: No las veo alli.\nB: Pues las habia puesto alli antes.",exampleSrc:"A: Where have you put the keys?\nB: I put them on the table.\nA: I don't see them there.\nB: Well, I had put them there before.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"abierto",src:"opened/open",pos:"noun",gender:null,phonetic:"ah-BYEHR-toh",note:"Irregular participle of abrir.",example:"A: ¿Quien ha abierto la ventana?\nB: Yo la he abierto porque hacia calor.\nA: Esta bien, pero cierra cuando salgas.\nB: De acuerdo, lo hare.",exampleSrc:"A: Who opened the window?\nB: I opened it because it was hot.\nA: That's fine, but close it when you leave.\nB: Alright, I will.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"roto",src:"broken",pos:"noun",gender:null,phonetic:"RROH-toh",note:"Irregular participle of romper.",example:"A: ¿Que ha pasado con el vaso?\nB: Se ha roto, lo siento mucho.\nA: No te preocupes, tengo mas.\nB: Ten cuidado con los trozos.",exampleSrc:"A: What happened with the glass?\nB: It broke, I'm very sorry.\nA: Don't worry, I have more.\nB: Be careful with the pieces.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"mc",q:"What is the past participle of 'hablar'?",opts:["hablado","hablido","habledo","habludo"],ans:"hablado",hint:"Regular -ar verbs drop the ending and add -ado."},
        {type:"mc",q:"Which is the correct irregular participle of 'hacer'?",opts:["hacido","hecho","hacedo","hacado"],ans:"hecho",hint:"This common irregular form doesn't follow the regular pattern at all."},
        {type:"fb",opts:["escrito","escribido","escribado","escrituo"],hint:"This verb has an irregular participle ending in -ito.",s:"El participio de 'escribir' es {1}.",a:["escrito"]},
        {type:"fb",opts:["visto","veido","vido","verido"],hint:"The participle of ver is completely irregular.",s:"¿Has {1} la nueva pelicula de terror?",a:["visto"]},
        {type:"match",pairs:[
          {trg:"hecho",src:"done (hacer)"},
          {trg:"dicho",src:"said (decir)"},
          {trg:"escrito",src:"written (escribir)"},
          {trg:"visto",src:"seen (ver)"},
          {trg:"puesto",src:"put (poner)"},
          {trg:"abierto",src:"opened (abrir)"}
        ]},
        {type:"mc",q:"'Se ha roto el plato.' What does 'roto' mean here?",opts:["rotated","returned","broken","removed"],ans:"broken",hint:"Think about what happens to a plate that falls on the floor."}
  ]},
  {id:"esp20l2",title:"Habia Comido",icon:"⏪",xp:20,board:true,steps:[
        {type:"intro",title:"El Pluscuamperfecto",desc:"Learn to talk about actions that happened before other past actions using habia + past participle.",goals:["Conjugate haber in the imperfect","Form pluscuamperfecto sentences","Understand 'past of the past'"]},
        {type:"tip",title:"Pluscuamperfecto Formation",deepDive:"The pluscuamperfecto expresses an action completed before another past action. English equivalent: 'had done'. Example: Cuando llegue, ya habian comido (When I arrived, they had already eaten). The first action (eating) happened before the second (arriving).",text:"Imperfect of haber + past participle:\n  yo habia + hablado/comido\n  tu habias + hablado/comido\n  el/ella habia + hablado/comido\n  nosotros habiamos + hablado/comido\n  vosotros habiais + hablado/comido\n  ellos habian + hablado/comido"},
        {type:"verb_table",title:"Haber (imperfect)",note:"This auxiliary never changes. The participle stays the same for all persons.",groups:[{label:"Singular",forms:["yo habia","tu habias","el/ella habia"],rows:[]},{label:"Plural",forms:["nosotros habiamos","vosotros habiais","ellos/ellas habian"],rows:[]}],label:"Auxiliary for pluscuamperfecto"},
        {type:"teach",trg:"habia comido",src:"I/he/she had eaten",pos:"intj",gender:null,phonetic:"ah-BEE-ah koh-MEE-doh",note:"Habia (imperfect of haber) + participle = pluscuamperfecto.",example:"A: ¿Tenias hambre cuando llegaste?\nB: No, ya habia comido antes de salir.\nA: ¿Que habias comido?\nB: Habia comido una ensalada rapida.",exampleSrc:"A: Were you hungry when you arrived?\nB: No, I had already eaten before leaving.\nA: What had you eaten?\nB: I had eaten a quick salad.",funFact:"Pluperfect (pluscuamperfecto): había + past participle. Marks an action completed BEFORE another past action. 'Había comido cuando llegó'; I had eaten before he arrived."},
        {type:"teach",trg:"habias estudiado",src:"you had studied",pos:"intj",gender:null,phonetic:"ah-BEE-ahs ehs-too-dee-AH-doh",note:"Tu form: habias + participle.",example:"A: ¿Aprobaste el examen?\nB: Si, porque habias estudiado mucho, ¿no?\nA: Bueno, habia estudiado toda la semana.\nB: Se nota, sacaste muy buena nota.",exampleSrc:"A: Did you pass the exam?\nB: Yes, because you had studied a lot, right?\nA: Well, I had studied all week.\nB: It shows, you got a very good grade.",funFact:"Second-person pluperfect. 'Habías estudiado antes del examen'; had you studied before the exam? The 'yo' and 'él' forms are identical (había); tú gets -s."},
        {type:"teach",trg:"habiamos llegado",src:"we had arrived",pos:"intj",gender:null,phonetic:"ah-BEE-ah-mohs yeh-GAH-doh",note:"Nosotros form: habiamos + participle.",example:"A: ¿Por que no visteis la pelicula desde el principio?\nB: Porque habiamos llegado tarde al cine.\nA: ¿Cuanto tarde?\nB: Habiamos llegado veinte minutos tarde.",exampleSrc:"A: Why didn't you see the movie from the beginning?\nB: Because we had arrived late to the cinema.\nA: How late?\nB: We had arrived twenty minutes late.",funFact:"First-person plural pluperfect. Nosotros uses habíamos (with accent on í). 'Habíamos llegado temprano'; we had arrived early."},
        {type:"teach",trg:"habian terminado",src:"they had finished",pos:"intj",gender:null,phonetic:"ah-BEE-ahn tehr-mee-NAH-doh",note:"Ellos/ellas form: habian + participle.",example:"A: ¿Pudisteis hablar con los estudiantes?\nB: No, ya habian terminado la clase.\nA: ¿Habian terminado temprano?\nB: Si, habian terminado media hora antes.",exampleSrc:"A: Were you able to talk to the students?\nB: No, they had already finished the class.\nA: Had they finished early?\nB: Yes, they had finished half an hour before.",funFact:"Third-person plural / ustedes pluperfect. Common in news reporting: 'los investigadores habían terminado el análisis' (the investigators had finished the analysis)."},
        {type:"mc",q:"'Cuando llegue, Maria ya habia ___.' Which participle completes this?",opts:["salido","salir","sale","salio"],ans:"salido",hint:"After habia, you need the past participle form, not the infinitive or conjugated verb."},
        {type:"fb",opts:["habiamos","habian","habia","habias"],hint:"The nosotros form of the imperfect haber has a specific ending.",s:"Nosotros ya {1} desayunado cuando sono el telefono.",a:["habiamos"]},
        {type:"mc",q:"Which sentence correctly uses the pluscuamperfecto?",opts:["Ella ha vivido en Paris antes de mudarse.","Ella habia vivido en Paris antes de mudarse.","Ella vivio en Paris antes de mudarse.","Ella vivia en Paris antes de mudarse."],ans:"Ella habia vivido en Paris antes de mudarse.",hint:"You need the form that expresses something completed before another past event."},
        {type:"fb",opts:["habias","habia","habian","habiamos"],hint:"The tu form of imperfect haber matches your subject.",s:"¿Tu ya {1} visto esa pelicula antes?",a:["habias"]},
        {type:"drag_fill",hint:"Two-part compound tense: imperfect haber + past participle.",s:"Ellos {1} {2} toda la comida antes de que yo llegara.",blanks:{"1":"habian","2":"comido"},pool:["habian","comido","habia","comer","comieron"]},
        {type:"mc",q:"'Los ninos ya habian hecho la tarea.' What does this mean?",opts:["The children will do the homework.","The children are doing the homework.","The children had already done the homework.","The children always do the homework."],ans:"The children had already done the homework.",hint:"Habian hecho refers to a completed action in the past, before another moment."},
        {type:"match",pairs:[
          {trg:"habia comido",src:"I/he/she had eaten"},
          {trg:"habias estudiado",src:"you had studied"},
          {trg:"habiamos llegado",src:"we had arrived"},
          {trg:"habian terminado",src:"they had finished"},
          {trg:"habia dicho",src:"I/he/she had said"},
          {trg:"habias escrito",src:"you had written"}
        ]},
        {type:"fb",opts:["hecho","hacido","hacer","hizo"],hint:"The participle of hacer is irregular.",s:"Cuando empezamos la reunion, el jefe ya habia {1} la decision.",a:["hecho"]},
        {type:"mc",q:"Which form of 'haber' completes: '___ habias leido el libro antes del examen?'",opts:["¿Ellos","¿El","¿Nosotros","¿Tu"],ans:"¿Tu",hint:"Match the subject pronoun to the verb form habias."},
        {type:"fb",opts:["habia","habias","habian","habiamos"],hint:"Maria is third person singular. Which form of haber fits?",s:"Maria nunca {1} viajado a Japon antes de ese ano.",a:["habia"]},
        {type:"mc",q:"'Habiamos preparado todo antes de la fiesta.' Who had prepared?",opts:["We had prepared.","They had prepared.","I had prepared.","You had prepared."],ans:"We had prepared.",hint:"Habiamos is the nosotros form of the imperfect haber."}
  ]},
  {id:"esp20l3",title:"Cuando Llegue...",icon:"📖",xp:20,board:true,steps:[
        {type:"intro",title:"Secuenciar Eventos Pasados",desc:"Learn to sequence events in the past: what happened first, what happened next.",goals:["Use pluscuamperfecto for the earlier event","Combine with indefinido for the later event","Use 'ya', 'todavia no', 'antes de'"]},
        {type:"teach",trg:"ya",src:"already",pos:"adv",gender:null,phonetic:"yah",note:"Ya signals an action already completed before another.",example:"A: ¿Llamaste a Pedro?\nB: Si, pero cuando lo llame, ya habia salido.\nA: ¿A que hora habia salido?\nB: Ya habia salido a las tres.",exampleSrc:"A: Did you call Pedro?\nB: Yes, but when I called him, he had already left.\nA: What time had he left?\nB: He had already left at three.",funFact:"'Ya' is one of Spanish's most overloaded words: 'already', 'now', 'OK', 'right away', and as a confirmation ('ya lo sé' = I know). Tone and context do all the disambiguating."},
        {type:"teach",trg:"todavia no",src:"not yet",pos:"intj",gender:null,phonetic:"toh-dah-BEE-ah noh",note:"Todavia no + pluscuamperfecto = hadn't done something yet.",example:"A: ¿Ya habias cenado cuando llego Ana?\nB: No, todavia no habia cenado.\nA: Entonces cenasteis juntos, ¿no?\nB: Si, fue muy agradable.",exampleSrc:"A: Had you already had dinner when Ana arrived?\nB: No, I hadn't had dinner yet.\nA: So you had dinner together, right?\nB: Yes, it was very nice.",funFact:"Literally 'still not.' Used with pluperfect for 'had not yet' constructions. 'Todavía no había llegado'; he still hadn't arrived. Strong pluperfect trigger."},
        {type:"teach",trg:"antes de salir",src:"before leaving",pos:"verb",gender:null,phonetic:"AHN-tehs deh sah-LEER",note:"Antes de + infinitive for the later action.",example:"A: ¿Desayunaste esta manana?\nB: Si, habia desayunado antes de salir de casa.\nA: ¿Que habias comido?\nB: Habia comido tostadas con cafe.",exampleSrc:"A: Did you have breakfast this morning?\nB: Yes, I had had breakfast before leaving the house.\nA: What had you eaten?\nB: I had eaten toast with coffee.",funFact:"Spanish uses 'antes de + infinitive' where English uses '-ing' after 'before.' 'Antes de salir' (before leaving), not 'antes saliendo.' A classic false-friend trap for English speakers."},
        {type:"tip",title:"Past Sequencing Pattern",deepDive:"The pluscuamperfecto always marks the EARLIER of two past events. The indefinido marks the LATER or reference event. Think of it as two layers of past: the indefinido is your 'past viewpoint' and the pluscuamperfecto goes even further back.",text:"Event 1 (earlier): pluscuamperfecto\n  Habia desayunado (I had eaten breakfast)\nEvent 2 (later): indefinido\n  ...cuando sali de casa (...when I left the house)\nFull: Habia desayunado cuando sali de casa."},
        {type:"teach",trg:"cuando llegue",src:"when I arrived",pos:"intj",gender:null,phonetic:"KWAHN-doh yeh-GEH",note:"Cuando + indefinido sets the reference point in the past.",example:"A: ¿Que paso cuando llegaste a la fiesta?\nB: Cuando llegue, todos ya habian empezado a bailar.\nA: ¿Llegaste muy tarde?\nB: Si, habia salido tarde del trabajo.",exampleSrc:"A: What happened when you arrived at the party?\nB: When I arrived, everyone had already started dancing.\nA: Did you arrive very late?\nB: Yes, I had left work late.",funFact:"Preterite of llegar. In pluperfect contexts, 'cuando + preterite' marks the moment relative to which the pluperfect action happened earlier. Always triggers hint at temporal layering."},
        {type:"mc",q:"'Cuando llegue al cine, la pelicula ya habia ___.' Which fits?",opts:["empezado","empezar","empezo","empezaba"],ans:"empezado",hint:"After habia, you always need the participle form."},
        {type:"fb",opts:["habia","he","habian","habias"],hint:"First person singular: which imperfect form of haber?",s:"Cuando Maria llamo, yo ya {1} salido de casa.",a:["habia"]},
        {type:"mc",q:"Which sentence correctly sequences two past events?",opts:["Hemos comido cuando llegaron los invitados.","Habiamos comido cuando llegaron los invitados.","Comiamos cuando llegaron los invitados.","Comemos cuando llegaron los invitados."],ans:"Habiamos comido cuando llegaron los invitados.",hint:"The earlier event needs the compound tense with habia."},
        {type:"drag_fill",hint:"Reference point in indefinido, earlier action in pluscuamperfecto.",s:"Cuando {1} al restaurante, mis amigos ya {2} {3}.",blanks:{"1":"llegue","2":"habian","3":"pedido"},pool:["llegue","habian","pedido","llego","habia","pedir"]},
        {type:"fb",opts:["habia","habias","habian","ha"],hint:"Pedro is third person singular. Think about the imperfect form.",s:"Pedro todavia no {1} terminado el proyecto cuando lo llamaron.",a:["habia"]},
        {type:"mc",q:"'Antes de mudarse a Madrid, Laura habia vivido en Barcelona.' What happened first?",opts:["Laura visited Barcelona.","Laura moved to Madrid.","Laura lived in Barcelona.","Laura left Madrid."],ans:"Laura lived in Barcelona.",hint:"The pluscuamperfecto action happened before the other past action."},
        {type:"drag_fill",hint:"First word is a time marker meaning 'before'. Then the compound tense.",s:"{1} de ir al examen, yo {2} {3} toda la noche.",blanks:{"1":"Antes","2":"habia","3":"estudiado"},pool:["Antes","habia","estudiado","Despues","habian","estudiar"]},
        {type:"mc",q:"'No pudimos entrar porque habian cerrado la puerta.' Why couldn't they enter?",opts:["The door will be closed.","The door was being closed.","They were closing the door.","The door had been closed before they arrived."],ans:"The door had been closed before they arrived.",hint:"Habian cerrado expresses something completed ___ they tried to enter."},
        {type:"fb",opts:["habian","habia","habias","habiamos"],hint:"Los estudiantes is third person plural.",s:"Los estudiantes ya {1} leido el libro antes del examen.",a:["habian"]},
        {type:"match",pairs:[
          {trg:"Cuando llegue, ya habian comido.",src:"When I arrived, they had already eaten."},
          {trg:"Todavia no habia terminado.",src:"He/she hadn't finished yet."},
          {trg:"Antes de salir, habia llamado.",src:"Before leaving, he/she had called."},
          {trg:"Ya habiamos visto la pelicula.",src:"We had already seen the movie."}
        ]},
        {type:"mc",q:"Choose the correct pair: 'Cuando ___ al parque, ya habia ___ de llover.'",opts:["llegamos / dejado","llegamos / dejar","llegabamos / dejado","hemos llegado / dejado"],ans:"llegamos / dejado",hint:"Reference point in indefinido, earlier event needs habia + participle."},
        {type:"fb",opts:["cerrado","cerrar","cerraron","cerraba"],hint:"After habian you need the past participle of cerrar.",s:"Ya habian {1} la tienda cuando quisimos comprar algo.",a:["cerrado"]}
  ]},
  {id:"esp20l4",title:"Antes de Que...",icon:"🔗",xp:20,board:true,steps:[
        {type:"intro",title:"Conectores de Secuencia",desc:"Master advanced time connectors for sequencing past events with antes de que, despues de que, and more.",goals:["Use 'antes de que' with subjunctive","Use 'despues de que' with past tenses","Combine multiple past tenses fluently"]},
        {type:"teach",trg:"antes de que",src:"before (someone else did)",pos:"intj",gender:null,phonetic:"AHN-tehs deh keh",note:"Antes de que + subjunctive. Used when two different subjects are involved.",example:"A: ¿Preparaste todo para la fiesta?\nB: Si, prepare todo antes de que llegaran los invitados.\nA: ¿Habias decorado la casa?\nB: Si, habia decorado todo antes de que vinieran.",exampleSrc:"A: Did you prepare everything for the party?\nB: Yes, I prepared everything before the guests arrived.\nA: Had you decorated the house?\nB: Yes, I had decorated everything before they came.",funFact:"Subjunctive trigger always. 'Antes de que + subjunctive': 'antes de que llegue' (before he arrives). Always, even when the event will definitely happen."},
        {type:"teach",trg:"despues de que",src:"after (something happened)",pos:"intj",gender:null,phonetic:"dehs-PWEHS deh keh",note:"Despues de que + indicative for past events that actually happened.",example:"A: ¿Que hiciste despues de que termino la clase?\nB: Despues de que termino, fui a la biblioteca.\nA: ¿Ya habias estudiado antes?\nB: No, no habia estudiado nada todavia.",exampleSrc:"A: What did you do after the class ended?\nB: After it ended, I went to the library.\nA: Had you studied before?\nB: No, I hadn't studied anything yet.",funFact:"Can take subjunctive OR indicative depending on whether the action is specific. Traditionally indicative (completed action), but modern usage often goes subjunctive by analogy with 'antes de que.'"},
        {type:"teach",trg:"cuando ya habia",src:"when (someone) had already",pos:"intj",gender:null,phonetic:"KWAHN-doh yah ah-BEE-ah",note:"Cuando + indefinido + ya habia + participle. Classic sequencing.",example:"A: ¿Por que no comiste en la cafeteria?\nB: Cuando llegue, ya habia cerrado.\nA: ¿Y que hiciste?\nB: Fui a un restaurante cercano.",exampleSrc:"A: Why didn't you eat at the cafeteria?\nB: When I arrived, it had already closed.\nA: And what did you do?\nB: I went to a nearby restaurant.",funFact:"'Cuando + pluperfect' marks the before-the-before: the earlier of two past moments. 'Cuando llegó, yo ya había comido' (by the time he arrived, I had already eaten)."},
        {type:"teach",trg:"todavia no habia",src:"still hadn't / hadn't yet",pos:"intj",gender:null,phonetic:"toh-dah-BEE-ah noh ah-BEE-ah",note:"Todavia no habia + participle = 'hadn't yet done something'.",example:"A: ¿Tu hermano ya habia conseguido trabajo?\nB: No, todavia no habia encontrado nada.\nA: ¿Y ahora?\nB: Ahora si, encontro trabajo la semana pasada.",exampleSrc:"A: Had your brother already gotten a job?\nB: No, he still hadn't found anything.\nA: And now?\nB: Now yes, he found a job last week.",funFact:"Negative pluperfect. Pairs with 'cuando' to mark non-completion at a past reference point. 'Todavía no había terminado cuando llegó'; hadn't finished yet when he arrived."},
        {type:"tip",title:"Antes de vs Antes de que",deepDive:"When the subject of both actions is the same person, use 'antes de' + infinitive (simpler). When different people are involved, you must use 'antes de que' + subjunctive. This rule applies to all time connectors: despues de/despues de que works the same way.",text:"Same subject: antes de + infinitive\n  Desayune antes de salir.\n  (I had breakfast before leaving.)\nDifferent subjects: antes de que + subjunctive\n  Prepare todo antes de que llegaran.\n  (I prepared everything before they arrived.)"},
        {type:"mc",q:"'Limpie la casa antes de que ___ mis padres.' Which form fits?",opts:["llegaran","llegaron","llegan","habian llegado"],ans:"llegaran",hint:"Antes de que requires a specific verb mood, not indicative."},
        {type:"fb",opts:["paso","pasara","pasa","habia pasado"],hint:"For a completed past event after despues de que, use the simple past.",s:"Despues de que {1} la tormenta, salimos a caminar.",a:["paso"]},
        {type:"mc",q:"Which sentence uses 'todavia no habia' correctly?",opts:["Todavia no habia terminado el trabajo cuando llega el jefe.","Todavia no habia terminado el trabajo cuando llego el jefe.","Todavia no ha terminado el trabajo cuando llego el jefe.","Todavia no termino el trabajo cuando llego el jefe."],ans:"Todavia no habia terminado el trabajo cuando llego el jefe.",hint:"Both verbs should be in past tenses, with the earlier action in pluscuamperfecto."},
        {type:"drag_fill",hint:"The train left earlier (pluscuamperfecto). We arrived later (antes de que + subjunctive).",s:"El tren ya {1} {2} antes de que {3} a la estacion.",blanks:{"1":"habia","2":"salido","3":"llegaramos"},pool:["habia","salido","llegaramos","habian","salir","llegamos"]},
        {type:"fb",opts:["habia","ha","habian","habias"],hint:"Anochecer is impersonal, like weather verbs. Third person singular.",s:"Cuando ya {1} anochecido, decidimos volver a casa.",a:["habia"]},
        {type:"mc",q:"'Estudie mucho antes de ___ al examen.' What completes this correctly?",opts:["habia ido","que fuera","ir","fui"],ans:"ir",hint:"Same subject for both actions, so you need the simpler construction."},
        {type:"drag_fill",hint:"Before we watched, we had already read. Different subjects need que + subjunctive.",s:"{1} de que {2} la pelicula, ya {3} {4} el final.",blanks:{"1":"Antes","2":"vieramos","3":"habiamos","4":"leido"},pool:["Antes","vieramos","habiamos","leido","Despues","vimos","habian","leer"]},
        {type:"mc",q:"'Despues de que Ana habia hablado, todos comprendieron.' What happened first?",opts:["Everyone spoke.","Everyone understood.","Ana left.","Ana spoke."],ans:"Ana spoke.",hint:"The pluscuamperfecto action is always the earlier of the two."},
        {type:"fb",opts:["fueron","fueran","iban","habian ido"],hint:"After despues de que for a completed past action, use the simple past.",s:"Recogimos todo despues de que se {1} los invitados.",a:["fueron"]},
        {type:"match",pairs:[
          {trg:"antes de que llegaran",src:"before they arrived"},
          {trg:"despues de que termino",src:"after it ended"},
          {trg:"cuando ya habia salido",src:"when he/she had already left"},
          {trg:"todavia no habia comido",src:"he/she still hadn't eaten"}
        ]},
        {type:"mc",q:"Which connector introduces an action that happened EARLIER than the main event?",opts:["antes de que","despues de que","mientras","porque"],ans:"antes de que",hint:"Think about which word means 'before' in the context of time."},
        {type:"fb",opts:["llegaran","llegaron","llegan","habian llegado"],hint:"Different subjects with antes de que require a specific verb mood.",s:"Termine de comer antes de que {1} mis amigos.",a:["llegaran"]}
  ]},
  {id:"esp20l5",title:"Dijo Que...",icon:"💬",xp:20,board:true,steps:[
        {type:"intro",title:"El Estilo Indirecto",desc:"Learn to report what someone said using dijo que, conto que, and pregunto si.",goals:["Report statements with dijo que","Report stories with conto que","Report questions with pregunto si"]},
        {type:"teach",trg:"dijo que",src:"he/she said that",pos:"intj",gender:null,phonetic:"DEE-hoh keh",note:"Most common way to report what someone said.",example:"A: ¿Que dijo el medico?\nB: Dijo que todo estaba bien.\nA: ¿De verdad? Eso es un alivio.\nB: Si, dijo que no habia ningun problema.",exampleSrc:"A: What did the doctor say?\nB: He said that everything was fine.\nA: Really? That's a relief.\nB: Yes, he said there was no problem.",funFact:"Reported speech with indicative. The 'que' introduces indirect speech. Tense shifts apply: present→imperfect, preterite→pluperfect, future→conditional; called 'consecutio temporum.'"},
        {type:"teach",trg:"me conto que",src:"he/she told me that",pos:"intj",gender:null,phonetic:"meh kohn-TOH keh",note:"Contar que = to tell/recount. More narrative than decir.",example:"A: ¿Sabes que le paso a Luis?\nB: Si, me conto que habia perdido su trabajo.\nA: ¿Cuando te lo conto?\nB: Me lo conto ayer por la noche.",exampleSrc:"A: Do you know what happened to Luis?\nB: Yes, he told me he had lost his job.\nA: When did he tell you?\nB: He told me last night.",funFact:"Contar has broader meaning than English 'tell.' Covers count (números), story-telling (cuentos), relating events. In reported speech, always indicative: 'me contó que venía.'"},
        {type:"teach",trg:"pregunto si",src:"he/she asked if/whether",pos:"intj",gender:null,phonetic:"preh-goon-TOH see",note:"For yes/no questions in reported speech, use 'si' (if/whether).",example:"A: ¿Que pregunto la profesora?\nB: Pregunto si habiamos hecho la tarea.\nA: ¿Y que le dijisteis?\nB: Le dijimos que si, que la habiamos hecho.",exampleSrc:"A: What did the teacher ask?\nB: She asked if we had done the homework.\nA: And what did you tell her?\nB: We told her yes, we had done it.",funFact:"Reported yes/no questions use 'si' + indicative. 'Preguntó si tenía dinero'; he asked whether I had money. No subjunctive because the asking happened as factual past event."},
        {type:"teach",trg:"pregunto que",src:"he/she asked what",pos:"intj",gender:null,phonetic:"preh-goon-TOH keh",note:"For wh-questions in reported speech, keep the question word.",example:"A: ¿Que te pregunto tu padre?\nB: Me pregunto que habia hecho todo el dia.\nA: ¿Y que le respondiste?\nB: Le dije que habia estado estudiando.",exampleSrc:"A: What did your father ask you?\nB: He asked me what I had done all day.\nA: And what did you answer?\nB: I told him I had been studying.",funFact:"Reported wh-questions use 'que' + indicative. 'Preguntó qué quería'; he asked what I wanted. The 'qué' keeps its accent (mark of question word) even in indirect speech."},
        {type:"tip",title:"Reported Speech Structure",deepDive:"In Spanish reported speech, when the reporting verb is in the past (dijo, conto, pregunto), the tenses inside the reported clause shift back: present becomes imperfect, preterite becomes pluscuamperfecto, future becomes conditional. This is called 'concordancia de tiempos' (sequence of tenses).",text:"Direct: 'Estoy cansada.' (I'm tired.)\nReported: Dijo que estaba cansada.\n  (She said she was tired.)\nDirect: '¿Has comido?'\nReported: Pregunto si habia comido.\n  (She asked if I had eaten.)\nKey: verbs shift one step back in time."},
        {type:"mc",q:"Pedro: 'Tengo hambre.' Reported: Pedro dijo que ___ hambre.",opts:["tenia","tiene","tendra","ha tenido"],ans:"tenia",hint:"Present tense in direct speech shifts to imperfect in reported speech."},
        {type:"fb",opts:["estaba","esta","estuvo","estara"],hint:"In reported speech past, present 'esta' shifts to the imperfect form.",s:"Maria dijo que {1} muy cansada despues del viaje.",a:["estaba"]},
        {type:"mc",q:"Ana: '¿Vienes a la fiesta?' Reported: Ana pregunto si ___ a la fiesta.",opts:["voy","iba","fui","ire"],ans:"iba",hint:"The present tense 'vienes' shifts back one tense in reported speech."},
        {type:"fb",opts:["si","que","como","cuando"],hint:"For reporting a yes/no question, you need the word meaning 'if/whether'.",s:"El profesor pregunto {1} habiamos entendido la leccion.",a:["si"]},
        {type:"drag_fill",hint:"Laura told me (past) + she had found (pluscuamperfecto).",s:"Laura me {1} que {2} {3} un trabajo nuevo.",blanks:{"1":"conto","2":"habia","3":"encontrado"},pool:["conto","habia","encontrado","cuenta","ha","encontrar"]},
        {type:"mc",q:"Direct: 'Ire manana.' Reported: Dijo que ___ al dia siguiente.",opts:["fue","iba","iria","ira"],ans:"iria",hint:"Future tense shifts to conditional in reported past speech."},
        {type:"fb",opts:["dijo","dice","dira","dicho"],hint:"The reporting verb should be in the simple past tense.",s:"Mi amigo me {1} que la pelicula era muy buena.",a:["dijo"]},
        {type:"match",pairs:[
          {trg:"Dijo que estaba enfermo.",src:"He said he was sick."},
          {trg:"Pregunto si venia.",src:"He asked if I was coming."},
          {trg:"Conto que habia viajado.",src:"He told that he had traveled."},
          {trg:"Dijo que iria manana.",src:"He said he would go tomorrow."}
        ]},
        {type:"mc",q:"'Mi madre me pregunto que habia hecho en la escuela.' What is the original question?",opts:["¿Que haras en la escuela?","¿Que hiciste en la escuela?","¿Que hacias en la escuela?","¿Que has hecho en la escuela?"],ans:"¿Que has hecho en la escuela?",hint:"The pluscuamperfecto in reported speech came from a present perfect original."},
        {type:"drag_fill",hint:"The boss said that the project would be ready. Past reporting + conditional.",s:"El jefe {1} {2} el proyecto {3} listo para el viernes.",blanks:{"1":"dijo","2":"que","3":"estaria"},pool:["dijo","que","estaria","dice","si","estaba"]},
        {type:"fb",opts:["habia","ha","habias","habian"],hint:"Third person singular reporting about herself. Which imperfect haber form?",s:"Mi hermana me conto que {1} conocido a alguien especial.",a:["habia"]},
        {type:"mc",q:"Direct: asking about someone's location. Reported: Pregunto ___ vivia.",opts:["donde","si","que","como"],ans:"donde",hint:"Wh-questions in reported speech keep the original question word. Location question word."}
  ]},
  {id:"esp20l6",title:"Cambio de Tiempos",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Concordancia de Tiempos",desc:"Master the tense shifts that happen in reported speech: present to imperfect, past to pluscuamperfecto, future to conditional.",goals:["Apply present to imperfect shift","Apply preterite to pluscuamperfecto shift","Apply future to conditional shift"]},
        {type:"tip",title:"Tense Backshift Rules",deepDive:"This system is called 'concordancia de tiempos' (sequence of tenses). It exists because when you report someone's words from a past perspective, all the time references shift back one step. The imperfect stays the same in reported speech because it already describes the past.",text:"When reporting past speech:\nPresente to Imperfecto\n  'Estoy bien' to Dijo que estaba bien.\nIndefinido to Pluscuamperfecto\n  'Fui ayer' to Dijo que habia ido.\nFuturo to Condicional\n  'Ire manana' to Dijo que iria.\nImperativo to Imperfecto de subjuntivo\n  '¡Ven!' to Dijo que viniera."},
        {type:"teach",trg:"presente a imperfecto",src:"present to imperfect (in reported speech)",pos:"part",gender:null,phonetic:"preh-SEHN-teh ah eem-pehr-FEHK-toh",note:"Direct 'trabajo mucho' becomes 'trabajaba mucho' in reported speech.",example:"A: ¿Que dijo Carlos?\nB: Dijo que trabajaba mucho.\nA: ¿Que dijo su esposa?\nB: Ella dijo que estaba preocupada por el.",exampleSrc:"A: What did Carlos say?\nB: He said he was working a lot.\nA: What did his wife say?\nB: She said she was worried about him.",funFact:"Consecutio temporum rule 1: present tense becomes imperfect when the reporting verb is past. 'Digo que viene' (I say he's coming) → 'Dije que venía' (I said he was coming)."},
        {type:"teach",trg:"indefinido a pluscuamperfecto",src:"preterite to pluperfect (in reported speech)",pos:"part",gender:null,phonetic:"een-deh-fee-NEE-doh ah ploos-kwahm-pehr-FEHK-toh",note:"Direct 'visite cinco ciudades' becomes 'habia visitado' in reported speech.",example:"A: ¿Que te conto Ana sobre su viaje?\nB: Me conto que habia visitado cinco ciudades.\nA: ¿Y que mas dijo?\nB: Dijo que habia conocido a gente muy interesante.",exampleSrc:"A: What did Ana tell you about her trip?\nB: She told me she had visited five cities.\nA: And what else did she say?\nB: She said she had met very interesting people.",funFact:"Rule 2: preterite becomes pluperfect in past-anchored reported speech. 'Dice que llegó' → 'Dijo que había llegado.' The reported past is pushed one layer deeper."},
        {type:"teach",trg:"futuro a condicional",src:"future to conditional (in reported speech)",pos:"part",gender:null,phonetic:"foo-TOO-roh ah kohn-dee-thyoh-NAHL",note:"Direct 'vendre a la cena' becomes 'vendria' in reported speech.",example:"A: ¿Que prometio tu hermano?\nB: Prometio que vendria a la cena.\nA: ¿Y Ana?\nB: Dijo que traeria el postre.",exampleSrc:"A: What did your brother promise?\nB: He promised he would come to dinner.\nA: And Ana?\nB: She said she would bring dessert.",funFact:"Rule 3: future becomes conditional in past-anchored reported speech. 'Dice que vendrá' (he'll come) → 'Dijo que vendría' (he'd come). English uses 'would' similarly."},
        {type:"mc",q:"Direct: 'Vivo en Madrid.' Reported: Dijo que ___ en Madrid.",opts:["vivia","vive","vivio","vivira"],ans:"vivia",hint:"Present tense shifts to which past tense in reported speech?"},
        {type:"mc",q:"Direct: 'Compre un coche nuevo.' Reported: Dijo que ___ un coche nuevo.",opts:["compraba","habia comprado","compro","ha comprado"],ans:"habia comprado",hint:"The preterite (simple past) shifts further back to the pluscuamperfecto."},
        {type:"fb",opts:["llegaria","llegaba","llego","habia llegado"],hint:"The future tense shifts to the conditional in reported speech.",s:"Direct: 'Llegare a las ocho.' Reported: Dijo que {1} a las ocho.",a:["llegaria"]},
        {type:"drag_fill",hint:"Third person plural reporting verb + present shifts to imperfect.",s:"Direct: 'Estamos contentos.' Reported: {1} que {2} {3}.",blanks:{"1":"Dijeron","2":"estaban","3":"contentos"},pool:["Dijeron","estaban","contentos","Dicen","estan","contento"]},
        {type:"mc",q:"Direct-speech present perfect ('he __ el trabajo') becomes: Dijo que habia ___ el trabajo.",opts:["terminaba","terminar","terminado","termino"],ans:"terminado",hint:"The present perfect shifts to pluscuamperfecto, keeping the same participle form of the main verb."},
        {type:"fb",opts:["iria","iba","fue","va"],hint:"Future 'ire' becomes which tense in reported speech?",s:"Maria dijo que {1} al medico la semana siguiente.",a:["iria"]},
        {type:"mc",q:"Which tense stays the SAME in reported speech?",opts:["Indefinido","Presente","Futuro","Imperfecto"],ans:"Imperfecto",hint:"One past tense doesn't need to shift because it's already describing the past."},
        {type:"drag_fill",hint:"Indefinido shifts to pluscuamperfecto: auxiliary + participle.",s:"Pedro: 'Comi paella.' Reported: Pedro dijo que {1} {2} paella.",blanks:{"1":"habia","2":"comido"},pool:["habia","comido","ha","comer","como"]},
        {type:"match",pairs:[
          {trg:"Estoy cansado. (direct)",src:"Dijo que estaba cansado."},
          {trg:"Fui al cine. (direct)",src:"Dijo que habia ido al cine."},
          {trg:"Vendre manana. (direct)",src:"Dijo que vendria."},
          {trg:"He comido. (direct)",src:"Dijo que habia comido."}
        ]},
        {type:"mc",q:"'Elena conto que sus padres habian vivido en Argentina.' What was Elena's original statement?",opts:["Mis padres vivieron en Argentina.","Mis padres vivian en Argentina.","Mis padres habian vivido en Argentina.","Mis padres viven en Argentina."],ans:"Mis padres vivieron en Argentina.",hint:"Pluscuamperfecto in reported speech comes from indefinido in direct speech."},
        {type:"fb",opts:["era","es","fue","seria"],hint:"Direct speech 'el examen es importante' shifts present to what tense?",s:"El profesor nos dijo que el examen {1} muy importante.",a:["era"]},
        {type:"mc",q:"Direct-speech plural present perfect: 'Hemos acabado.' Reported: Dijeron que habian ___.",opts:["terminar","terminado","terminaban","terminaron"],ans:"terminado",hint:"Present perfect shifts to pluscuamperfecto, keeping the same participle form. Synonymous with 'acabado.'"},
        {type:"fb",opts:["habia","ha","habias","habian"],hint:"Ana (third person singular) reporting her own past action with pluscuamperfecto.",s:"Ana dijo que {1} llamado tres veces pero nadie contesto.",a:["habia"]}
  ]},
  {id:"esp20l7",title:"Contando Historias",icon:"📚",xp:20,board:true,steps:[
        {type:"intro",title:"Narrativas Completas",desc:"Combine all three past tenses (indefinido, imperfecto, pluscuamperfecto) to tell complete stories.",goals:["Use indefinido for completed actions","Use imperfecto for background/description","Use pluscuamperfecto for prior events"]},
        {type:"tip",title:"The Three Past Tenses in Narrative",deepDive:"Think of a movie: the indefinido is the plot (what happens), the imperfecto is the scenery and atmosphere (what things looked/felt like), and the pluscuamperfecto is the flashback (what had happened before the current scene). Great storytellers weave all three together.",text:"Indefinido: main events, plot progression\n  Llegue, abri la puerta, entre.\nImperfecto: background, descriptions, ongoing\n  Llovia, hacia frio, estaba oscuro.\nPluscuamperfecto: flashbacks, prior events\n  Habia olvidado las llaves."},
        {type:"teach",trg:"Cuando era nino",src:"When I was a child",pos:"intj",gender:null,phonetic:"KWAHN-doh EH-rah NEE-nyoh",note:"Imperfecto for age, habitual past, and descriptions.",example:"A: ¿Vivias en esta ciudad de nino?\nB: No, cuando era nino vivia en un pueblo.\nA: ¿Cuando os mudasteis aqui?\nB: Nos mudamos cuando yo tenia diez anos.",exampleSrc:"A: Did you live in this city as a child?\nB: No, when I was a child I lived in a village.\nA: When did you move here?\nB: We moved when I was ten years old.",funFact:"Imperfect 'era' sets the past backdrop for a narrative. Pairs naturally with pluperfect for 'había + done something before' layers. Classic storytelling construction."},
        {type:"teach",trg:"de repente",src:"suddenly",pos:"noun",gender:null,phonetic:"deh rreh-PEHN-teh",note:"De repente introduces a sudden action (indefinido) into background (imperfecto).",example:"A: ¿Que paso en la excursion?\nB: Estabamos caminando tranquilamente y de repente empezo a llover.\nA: ¿Y que hicisteis?\nB: Corrimos a refugiarnos en una cueva.",exampleSrc:"A: What happened on the hike?\nB: We were walking calmly and suddenly it started to rain.\nA: And what did you do?\nB: We ran to take shelter in a cave.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"resulta que",src:"it turns out that",pos:"intj",gender:null,phonetic:"rreh-SOOL-tah keh",note:"Introduces an explanation using pluscuamperfecto for prior events.",example:"A: ¿Por que llego tarde Juan?\nB: Resulta que habia perdido el autobus.\nA: ¿Y como llego al final?\nB: Tuvo que tomar un taxi.",exampleSrc:"A: Why did Juan arrive late?\nB: It turns out he had missed the bus.\nA: And how did he get there in the end?\nB: He had to take a taxi.",funFact:"Discourse marker introducing surprise reveals in narratives. 'Resulta que era mi vecino'; it turns out he was my neighbor. Always takes indicative (the fact is now asserted)."},
        {type:"mc",q:"'Ayer ___ un dia precioso. El sol ___ y los pajaros ___.' Which tenses fit?",opts:["fue / brillaba / cantaban","era / brillo / cantaron","fue / brilla / cantan","habia sido / brillaba / cantaban"],ans:"fue / brillaba / cantaban",hint:"The day itself is a completed event, but the sun and birds are background description."},
        {type:"fb",opts:["despegado","despegar","despego","despegaba"],hint:"After habia, you need the past participle form.",s:"Cuando llegamos al aeropuerto, el avion ya habia {1}.",a:["despegado"]},
        {type:"mc",q:"Which combination is correct for: '___ mucho frio y ___ nieve porque ___ nevado toda la noche.'",opts:["Hizo / hubo / habia","Hacia / habia / habia","Hizo / habia / habia","Hacia / habia / hubo"],ans:"Hacia / habia / habia",hint:"Weather description (imperfecto) + result (imperfecto) + cause from before (pluscuamperfecto)."},
        {type:"drag_fill",hint:"Two completed events (indefinido) plus a flashback (pluscuamperfecto).",s:"Maria {1} al trabajo, pero {2} que {3} {4} las llaves en casa.",blanks:{"1":"llego","2":"descubrio","3":"habia","4":"dejado"},pool:["llego","descubrio","habia","dejado","llegaba","descubria","habian","dejar"]},
        {type:"mc",q:"In a story, the pluscuamperfecto is used for:",opts:["describing the setting and atmosphere","the main events of the story","events that happened before the story's main timeline","habitual actions in the past"],ans:"events that happened before the story's main timeline",hint:"Think about which tense represents the 'flashback' in a narrative."},
        {type:"fb",opts:["preparaba","prepare","habia preparado","preparo"],hint:"An ongoing background action interrupted by a sudden event uses the imperfect.",s:"Mientras yo {1} la cena, sono el telefono.",a:["preparaba"]},
        {type:"drag_fill",hint:"Main action (indefinido) + reason from before (pluscuamperfecto).",s:"El lunes {1} a trabajar temprano porque el jefe {2} {3} una reunion urgente.",blanks:{"1":"fui","2":"habia","3":"convocado"},pool:["fui","habia","convocado","iba","ha","convocar"]},
        {type:"mc",q:"'Estabamos cenando tranquilamente cuando de repente alguien llamo a la puerta. Era un vecino que habia visto humo.' Which tense is 'estabamos cenando'?",opts:["Condicional (hypothetical)","Indefinido (completed event)","Pluscuamperfecto (prior event)","Imperfecto (ongoing background)"],ans:"Imperfecto (ongoing background)",hint:"An ___ scene being described uses which type of past tense?"},
        {type:"fb",opts:["oyo","oia","habia oido","oye"],hint:"A sudden completed action in a narrative uses the simple past.",s:"Pedro me conto que de repente {1} un ruido muy fuerte.",a:["oyo"]},
        {type:"match",pairs:[
          {trg:"Llovia mucho. (background)",src:"Imperfecto"},
          {trg:"Abri la puerta. (action)",src:"Indefinido"},
          {trg:"Habia olvidado el paraguas. (prior)",src:"Pluscuamperfecto"},
          {trg:"De repente sono el telefono. (sudden)",src:"Indefinido"}
        ]},
        {type:"mc",q:"Choose the best narrative sequence: 'El sabado pasado ___ (ir) al museo. ___ (hacer) buen tiempo y mucha gente ___ (pasear) por el centro.'",opts:["fui / Hacia / paseaba","iba / Hizo / paseo","fui / Hizo / habia paseado","iba / Hacia / paseaba"],ans:"fui / Hacia / paseaba",hint:"Main event (indefinido) + weather and people are scene-setting (imperfecto)."},
        {type:"fb",opts:["empezo","empezaba","habia empezado","empieza"],hint:"A sudden interruption of an ongoing scene uses the simple past.",s:"Los ninos jugaban en el parque cuando de repente {1} a llover.",a:["empezo"]},
        {type:"drag_fill",hint:"We couldn't (indefinido) because they had said (pluscuamperfecto).",s:"No {1} ir a la playa porque {2} {3} que iba a llover.",blanks:{"1":"pudimos","2":"habian","3":"dicho"},pool:["pudimos","habian","dicho","podiamos","habia","decir"]}
  ]},
  {id:"esp20l8",title:"Repaso Final",icon:"🏁",xp:25,board:true,steps:[
        {type:"intro",title:"Repaso: Pluscuamperfecto y Estilo Indirecto",desc:"Comprehensive review combining pluscuamperfecto, past tense sequencing, and reported speech.",goals:["Demonstrate mastery of all three past tenses","Apply reported speech tense backshift","Sequence events accurately in narratives"]},
        {type:"mc",q:"Which is the correct pluscuamperfecto form of 'escribir' for 'nosotros'?",opts:["habiamos escrito","habiamos escribido","hemos escrito","habemos escrito"],ans:"habiamos escrito",hint:"Escribir has an irregular participle. Combine it with the nosotros imperfect of haber."},
        {type:"fb",opts:["ido","ir","fue","iba"],hint:"The participle of ir is a short, irregular form.",s:"Cuando llegue a la oficina, mi companero ya se habia {1}.",a:["ido"]},
        {type:"mc",q:"'Ana dijo que ___ enferma.' Which correctly reports 'Estoy enferma'?",opts:["esta","estaba","estuvo","estaria"],ans:"estaba",hint:"Present tense in direct speech shifts to imperfect when reported in the past."},
        {type:"drag_fill",hint:"They told me (past) + they had traveled (pluscuamperfecto).",s:"Mis padres me {1} que {2} {3} a Espana de jovenes.",blanks:{"1":"contaron","2":"habian","3":"viajado"},pool:["contaron","habian","viajado","cuentan","habia","viajar"]},
        {type:"mc",q:"'Antes de que empezara la pelicula, ya habiamos comprado las palomitas.' What happened first?",opts:["They entered the cinema.","The movie started.","They bought the popcorn.","They sat down."],ans:"They bought the popcorn.",hint:"The pluscuamperfecto marks the action that occurred first in time."},
        {type:"fb",opts:["habiamos","habia","habias","habian"],hint:"The professor asked us (nosotros). Which form of haber fits?",s:"El profesor pregunto si {1} entendido la explicacion.",a:["habiamos"]},
        {type:"mc",q:"'Hacia frio y llovia. Juan ___ que ___ el paraguas en casa.' Complete the narrative.",opts:["habia descubierto / olvido","descubria / olvido","descubrio / olvidaba","descubrio / habia olvidado"],ans:"descubrio / habia olvidado",hint:"Discovery is a completed event, forgetting happened before the discovery."},
        {type:"drag_fill",hint:"She said (past) + she had gone (pluscuamperfecto) + she was fine (imperfect).",s:"Laura {1} que {2} {3} al medico y que {4} bien.",blanks:{"1":"dijo","2":"habia","3":"ido","4":"estaba"},pool:["dijo","habia","ido","estaba","dice","ha","ir","esta"]},
        {type:"fb",opts:["abierto","abrir","abrido","abrio"],hint:"The participle of abrir is irregular. Think: a-b-i-e-r-t-o.",s:"Todavia no habian {1} la puerta cuando empezamos a llamar.",a:["abierto"]},
        {type:"mc",q:"Direct: 'Hare el examen el lunes.' Reported: Dijo que ___ el examen el lunes.",opts:["haria","hacia","hizo","habia hecho"],ans:"haria",hint:"Future tense shifts to conditional in past reported speech."},
        {type:"match",pairs:[
          {trg:"habia comido",src:"had eaten"},
          {trg:"dijo que estaba",src:"said he/she was"},
          {trg:"antes de que llegaran",src:"before they arrived"},
          {trg:"pregunto si sabia",src:"asked if he/she knew"},
          {trg:"todavia no habia visto",src:"still hadn't seen"},
          {trg:"resulta que habia perdido",src:"turns out he/she had lost"}
        ]},
        {type:"drag_fill",hint:"We arrived (indefinido) + there were many people (impersonal habia) + they had made a reservation (pluscuamperfecto).",s:"Cuando {1} al restaurante, {2} mucha gente porque {3} {4} una reserva especial.",blanks:{"1":"llegamos","2":"habia","3":"habian","4":"hecho"},pool:["llegamos","habia","habian","hecho","llegabamos","ha","han","hacer"]},
        {type:"mc",q:"Which full sentence correctly combines reported speech with pluscuamperfecto?",opts:["Mi amigo me cuenta que habia vivido en Peru durante tres anos.","Mi amigo me conto que habia vivido en Peru durante tres anos.","Mi amigo me conto que ha vivido en Peru durante tres anos.","Mi amigo me conto que vivio en Peru durante tres anos."],ans:"Mi amigo me conto que habia vivido en Peru durante tres anos.",hint:"Past reporting verb + pluscuamperfecto for the earlier lived experience."},
        {type:"fb",opts:["entregado","entregar","entrego","entregaba"],hint:"After habia, you need the regular past participle of entregar.",s:"El cartero dijo que ya habia {1} todas las cartas.",a:["entregado"]},
        {type:"drag_fill",hint:"Before the storm started (subjunctive) + the children had gone (pluscuamperfecto).",s:"{1} de que {2} la tormenta, los ninos ya se {3} {4} a dormir.",blanks:{"1":"Antes","2":"empezara","3":"habian","4":"ido"},pool:["Antes","empezara","habian","ido","Despues","empezo","habia","ir"]},
        {type:"mc",q:"In a narrative: 'Era una noche oscura. Todo estaba en silencio. De repente, ___ un grito.' Which fits?",opts:["se habia oido","se oia","se oyo","se oye"],ans:"se oyo",hint:"A sudden event breaking into a described scene uses which past tense?"},
        {type:"fb",opts:["habia","ha","habias","habian"],hint:"The grandfather (third person singular) recounting his past experience.",s:"El abuelo nos conto que de joven {1} vivido en muchos paises.",a:["habia"]}
  ]},
  {id:"esp20l8b",title:"Ley y Finanzas: Vocabulario",icon:"⚖️",xp:20,board:true,steps:[
        {type:"intro",title:"Legal & Financial Vocabulary",desc:"Vocabulario básico de leyes y finanzas.\nLearn essential legal and financial terms in Spanish.",goals:["Learn 12 legal/financial words","Practice with articles (el/la)","Use finance vocabulary in daily contexts"]},
        {type:"teach",trg:"el contrato",src:"the contract",pos:"noun",gender:"m",note:"el contrato (m.)\nfirmar un contrato = to sign a contract.\nla letra pequeña = the fine print.",example:"A: ¿Ya firmaste el contrato?\nB: Todavía no. Quiero leerlo bien primero.\nA: Buena idea. Siempre hay que leer la letra pequeña.\nB: Sí, voy a revisarlo con calma.",exampleSrc:"A: Did you already sign the contract?\nB: Not yet. I want to read it carefully first.\nA: Good idea. You should always read the fine print.\nB: Yes, I'll review it calmly.",funFact:"Cognate with English 'contract'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el seguro",src:"the insurance",pos:"noun",gender:"m",note:"el seguro (m.)\nseguro médico = health insurance.\nseguro de vida = life insurance.\nseguro de coche = car insurance.",example:"A: ¿Tienes seguro médico?\nB: Sí, lo pago cada mes.\nA: ¿Es caro?\nB: Regular. Pero es importante tenerlo.",exampleSrc:"A: Do you have health insurance?\nB: Yes, I pay it every month.\nA: Is it expensive?\nB: Average. But it's important to have it.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el impuesto",src:"the tax",pos:"noun",gender:"m",note:"el impuesto (m.)\nIVA = impuesto sobre el valor añadido (VAT).\nla declaración de impuestos = tax return.",example:"A: ¿Cuánto pagas de impuestos?\nB: Bastante. Casi el treinta por ciento.\nA: Es mucho, pero son necesarios.\nB: Sí, pagan los servicios públicos.",exampleSrc:"A: How much do you pay in taxes?\nB: Quite a lot. Almost thirty percent.\nA: That's a lot, but they're necessary.\nB: Yes, they pay for public services.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el banco",src:"the bank",pos:"noun",gender:"m",note:"el banco (m.)\nAlso means 'bench' (park bench).\nla cuenta bancaria = bank account.\nel cajero automático = ATM.",example:"A: Necesito ir al banco esta tarde.\nB: ¿Para qué?\nA: Quiero abrir una cuenta nueva.\nB: Yo cambié de banco el mes pasado.",exampleSrc:"A: I need to go to the bank this afternoon.\nB: What for?\nA: I want to open a new account.\nB: I switched banks last month.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el alquiler",src:"the rent",pos:"noun",gender:"m",note:"el alquiler (m.)\nalquilar = to rent.\nel/la inquilino/a = tenant.\nel/la propietario/a = landlord.",example:"A: ¿Cuánto pagas de alquiler?\nB: Ochocientos euros al mes.\nA: Es bastante caro para esta zona.\nB: Sí, pero el piso es grande y luminoso.",exampleSrc:"A: How much do you pay in rent?\nB: Eight hundred euros a month.\nA: That's quite expensive for this area.\nB: Yes, but the apartment is big and bright.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el préstamo",src:"the loan",pos:"verb",gender:null,note:"el préstamo (m.)\npedir un préstamo = to take out a loan.\npagar un préstamo = to pay back a loan.",example:"A: Pedí un préstamo para comprar un coche.\nB: ¿En qué banco?\nA: En el banco central. El interés es bajo.\nB: ¿Cuánto tiempo tienes para pagarlo?",exampleSrc:"A: I took out a loan to buy a car.\nB: At which bank?\nA: At the central bank. The interest is low.\nB: How long do you have to pay it back?",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"los ahorros",src:"the savings",pos:"noun",gender:"pl",note:"los ahorros (m. plural)\nahorrar = to save (money).\nla cuenta de ahorros = savings account.",example:"A: Estoy usando mis ahorros para viajar.\nB: ¿No te preocupa gastarlos?\nA: Un poco, pero la vida es corta.\nB: Tienes razón. Hay que disfrutar también.",exampleSrc:"A: I'm using my savings to travel.\nB: Aren't you worried about spending them?\nA: A little, but life is short.\nB: You're right. You have to enjoy too.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"el interés",src:"the interest (financial)",pos:"noun",gender:"m",note:"el interés (m.)\nDouble meaning: interest (financial) AND interest (curiosity).\nla tasa de interés = interest rate.",example:"A: ¿Cuál es el interés del préstamo?\nB: El tres por ciento anual.\nA: No está mal para estos tiempos.\nB: Sí, comparé varias opciones.",exampleSrc:"A: What's the interest on the loan?\nB: Three percent annually.\nA: Not bad for these times.\nB: Yes, I compared several options.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la multa",src:"the fine / penalty",pos:"noun",gender:"f",note:"la multa (f.)\nmultar = to fine.\nuna multa de tráfico = a traffic fine.",example:"A: Me pusieron una multa de aparcamiento.\nB: ¿Cuánto tienes que pagar?\nA: Cincuenta euros.\nB: Qué fastidio. Ten más cuidado la próxima vez.",exampleSrc:"A: I got a parking fine.\nB: How much do you have to pay?\nA: Fifty euros.\nB: What a pain. Be more careful next time.",funFact:"Fine/penalty. From Latin 'multa' (penalty). Traffic fines are 'multas de tráfico.' Also: 'multar' (to fine), an active verb derived from the noun."},
        {type:"teach",trg:"la ley",src:"the law",pos:"noun",gender:"f",note:"la ley (f.)\nPlural: las leyes.\nel abogado / la abogada = lawyer.\nlegal / ilegal = legal / illegal.",example:"A: La nueva ley entra en vigor en enero.\nB: ¿De qué trata?\nA: Sobre protección del medio ambiente.\nB: Me parece muy bien. Era necesaria.",exampleSrc:"A: The new law takes effect in January.\nB: What is it about?\nA: About environmental protection.\nB: I think that's great. It was necessary.",funFact:"Law. From Latin 'lex/legis.' Same root as 'legal,' 'legislate,' 'legitimate.' In Spanish 'ley' keeps a single syllable; the Latin stem 'leg-' shows in derived words (ley → legal)."},
        {type:"teach",trg:"el recibo",src:"the receipt",pos:"noun",gender:"m",note:"el recibo (m.)\nAlso: la factura (invoice/bill).\nel ticket (informal, from English).",example:"A: ¿Me puede dar el recibo, por favor?\nB: Sí, aquí tiene.\nA: Gracias. Lo necesito para la devolución.\nB: Tiene treinta días para devolver el producto.",exampleSrc:"A: Can you give me the receipt, please?\nB: Yes, here you go.\nA: Thanks. I need it for the return.\nB: You have thirty days to return the product.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el sueldo",src:"the salary",pos:"noun",gender:"m",note:"el sueldo (m.)\nAlso: el salario.\ncobrar = to receive payment.\nla nómina = payroll / pay slip.",example:"A: ¿Cobras tu sueldo a fin de mes?\nB: Sí, el día veinticinco.\nA: ¿Es suficiente para vivir bien?\nB: Más o menos. Los gastos son altos.",exampleSrc:"A: Do you get your salary at the end of the month?\nB: Yes, on the twenty-fifth.\nA: Is it enough to live well?\nB: More or less. Expenses are high.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"mc",q:"Necesito ir al ___ para abrir una cuenta nueva.",opts:["banco","alquiler","impuesto","recibo"],ans:"banco",hint:"A financial institution where you keep your money."},
        {type:"mc",q:"¿Ya firmaste el ___ de tu nuevo trabajo?",opts:["seguro","contrato","préstamo","recibo"],ans:"contrato",hint:"A formal written agreement between two parties."},
        {type:"fb",opts:["alquiler","impuesto","seguro","interés"],hint:"The monthly payment you make to live in a place you don't own.",s:"Pago ochocientos euros de {1} cada mes por mi piso.",a:["alquiler"]},
        {type:"mc",q:"Pedí un ___ al banco para comprar una casa.",opts:["sueldo","ahorro","préstamo","recibo"],ans:"préstamo",hint:"Money that the bank lends you that you pay back over time."},
        {type:"fb",opts:["multa","ley","factura","cuenta"],hint:"A monetary penalty for breaking a rule.",s:"Me pusieron una {1} porque aparqué mal el coche.",a:["multa"]},
        {type:"match",pairs:[{trg:"el contrato",src:"contract"},{trg:"el seguro",src:"insurance"},{trg:"el impuesto",src:"tax"},{trg:"el préstamo",src:"loan"},{trg:"la multa",src:"fine"}]},
        {type:"mc",q:"Estoy ahorrando dinero. Tengo buenos ___.",opts:["recibos","intereses","impuestos","ahorros"],ans:"ahorros",hint:"Money you have put aside for the future."},
        {type:"fb",opts:["ley","multa","cuenta","factura"],hint:"An official rule that everyone in a country must follow.",s:"La nueva {1} prohíbe fumar en los parques públicos.",a:["ley"]},
        {type:"mc",q:"¿Me puede dar el ___, por favor? Lo necesito para la empresa.",opts:["recibo","sueldo","banco","interés"],ans:"recibo",hint:"A paper proving you paid for something."},
        {type:"match",pairs:[{trg:"el alquiler",src:"rent"},{trg:"los ahorros",src:"savings"},{trg:"el interés",src:"interest"},{trg:"la ley",src:"law"},{trg:"el sueldo",src:"salary"}]}
  ,{type:"match",pairs:[{trg:"el participio pasado",src:"the past participle"},{trg:"roto",src:"broken"}]}]}
]};
